import numpy as np
try:
    from psychopy import core, visual
except ImportError:
    print("Psychopy not downloaded.")

class MainExpInterface:
    def __init__(self, fullscr=False):
        if fullscr:
            self.win = visual.Window(fullscr=True, color="#131722", units="norm")
            self.win_width, self.win_height = self.win.size
        else:
            self.win_width, self.win_height = 800, 600
            self.win = visual.Window(size=[self.win_width, self.win_height],
                                     fullscr=False, color="#131722", units="norm")

        self.fixation_cross = visual.TextStim(text="+", win=self.win,
                                               color="white", height=0.2)

    def fix_cross(self, duration=10.0):
        self.fixation_cross.draw()
        self.win.flip()
        core.wait(duration)

    def build_chart(self, values):
        margin_left   = -1 + 2 * 0.10
        margin_right  = -1 + 2 * 0.85
        margin_bottom = -1 + 2 * 0.12
        margin_up     = -1 + 2 * 0.88

        baseline = values[0]
        bottom_y = baseline * 0.985
        top_y    = baseline * 1.015

        def to_x(i):
            return np.interp(i, (0, len(values) - 1), (margin_left, margin_right))

        def to_y(v):
            return np.interp(v, (bottom_y, top_y), (margin_bottom, margin_up))

        mid_y = to_y(baseline)

        # ── Grid lines ──────────────────────────────────────────────
        grid_color = "#1e2130"
        for i in range(5):
            frac = i / 4
            gy = margin_bottom + frac * (margin_up - margin_bottom)
            grid = visual.Line(self.win,
                               start=(margin_left,  gy),
                               end=(margin_right, gy),
                               lineColor=grid_color, lineWidth=1)
            grid.draw()

        for i in range(9):
            frac = i / 8
            gx = margin_left + frac * (margin_right - margin_left)
            vgrid = visual.Line(self.win,
                                start=(gx, margin_bottom),
                                end=(gx, margin_up),
                                lineColor=grid_color, lineWidth=1)
            vgrid.draw()

        # ── Axes ────────────────────────────────────────────────────
        axis_color = "#2a2e39"
        visual.Line(self.win,
                    start=(margin_left, margin_bottom),
                    end=(margin_right, margin_bottom),
                    lineColor=axis_color, lineWidth=2).draw()
        visual.Line(self.win,
                    start=(margin_left, margin_bottom),
                    end=(margin_left, margin_up),
                    lineColor=axis_color, lineWidth=2).draw()

        # ── Baseline (dashed midline) ────────────────────────────────
        # PsychoPy doesn't natively support dashed lines, so approximate
        # with short segments
        dash_len = (margin_right - margin_left) / 60
        for seg in range(30):
            seg_start = margin_left + seg * 2 * dash_len
            seg_end   = seg_start + dash_len
            if seg_end > margin_right:
                seg_end = margin_right
            visual.Line(self.win,
                        start=(seg_start, mid_y),
                        end=(seg_end,   mid_y),
                        lineColor="#4a4f68", lineWidth=1).draw()

        # ── Y-axis labels ────────────────────────────────────────────
        label_x = margin_left - 0.06
        for i in range(5):
            frac = i / 4
            v = bottom_y + frac * (top_y - bottom_y)
            gy = margin_bottom + frac * (margin_up - margin_bottom)
            label = visual.TextStim(
                win=self.win, text=f"{v:.2f}",
                pos=(label_x, gy), color="#4a4f68",
                height=0.04, alignText="right"
            )
            label.draw()

        # ── Filled area (green above baseline, red below) ────────────
        GREEN_FILL = [38/255,  166/255,  91/255]
        RED_FILL   = [239/255,  83/255,  80/255]
        OPACITY    = 0.30

        xs = [to_x(i) for i in range(len(values))]
        ys = [to_y(v) for v in values]

        for i in range(1, len(values)):
            x0, y0 = xs[i-1], ys[i-1]
            x1, y1 = xs[i],   ys[i]
            above0 = values[i-1] >= baseline
            above1 = values[i]   >= baseline

            if above0 == above1:
                color = GREEN_FILL if above0 else RED_FILL
                verts = [(x0, mid_y), (x0, y0), (x1, y1), (x1, mid_y)]
            else:
                # Find where the line crosses the baseline
                t  = (baseline - values[i-1]) / (values[i] - values[i-1])
                xi = x0 + t * (x1 - x0)

                # Draw both halves
                for (va, xa, ya, xb, yb) in [
                    (values[i-1], x0, y0, xi, mid_y),
                    (values[i],   xi, mid_y, x1, y1),
                ]:
                    c = GREEN_FILL if va >= baseline else RED_FILL
                    seg_verts = [(xa, mid_y), (xa, ya), (xb, yb), (xb, mid_y)]
                    poly = visual.ShapeStim(
                        self.win, vertices=seg_verts,
                        closeShape=True, lineWidth=0,
                        fillColor=c, opacity=OPACITY
                    )
                    poly.draw()
                continue

            poly = visual.ShapeStim(
                self.win, vertices=verts,
                closeShape=True, lineWidth=0,
                fillColor=color, opacity=OPACITY
            )
            poly.draw()

        # ── Price line ───────────────────────────────────────────────
        vertices = list(zip(xs, ys))
        line = visual.ShapeStim(self.win, vertices=vertices[:2],
                                closeShape=False, lineColor="#2196f3",
                                fillColor=None, lineWidth=2)

        for i in range(2, len(values) + 1):
            line.vertices = vertices[:i]
            # Redraw static elements only when needed — for a real experiment
            # you'd pre-render these; this keeps the logic clear.
            line.draw()
            self.win.flip()
            core.wait(0.01)

        # ── Final frame: last-price marker ───────────────────────────
        last_y = ys[-1]
        last_color = "#26a65b" if values[-1] >= baseline else "#ef5350"

        visual.Line(self.win,
                    start=(margin_left,  last_y),
                    end=(margin_right, last_y),
                    lineColor=last_color, lineWidth=1).draw()
        visual.Circle(self.win, radius=0.012, pos=(margin_right, last_y),
                      fillColor=last_color, lineColor=None).draw()

        change = values[-1] - baseline
        pct    = change / baseline * 100
        sign   = "+" if change >= 0 else ""
        label_text = f"{values[-1]:.3f}  {sign}{change:.3f} ({sign}{pct:.2f}%)"
        visual.TextStim(
            win=self.win, text=label_text,
            pos=(0, margin_up + 0.07),
            color=last_color, height=0.05
        ).draw()

        self.win.flip()
        core.wait(20.0)

